const express = require('express');
const mongoose = require('mongoose');

const app = express();
app.use(express.json());

const queryBuilder = async (model, filter = {}, projection = {}, sort = {}) => {
    try {
        const results = await model.find(filter).select(projection).sort(sort);
        return results;
    } catch (error) {
        throw new Error('Query execution failed: ' + error.message);
    }
};

// Example Mongoose model
const User = mongoose.model('User', new mongoose.Schema({
    name: String,
    age: Number,
    password: String,
    createdAt: { type: Date, default: Date.now },
}));

app.post('/api/users/query', async (req, res) => {
    const { filter, projection, sort } = req.body;
    try {
        const results = await queryBuilder(User, filter, projection, sort);
        res.json(results);
    } catch (error) {
        res.status(500).json({ message: error.message });
    }
});

